 3	function buildSelectedClipsPrompt(
 4	  selectedClips: SelectedClipPayload[] | undefined,
 5	  timelineSummary: string,
 6	): string {
 7	  if (!selectedClips?.length) {
 8	    return "";
 9	  }
10	
11	  const timelineLines = timelineSummary.split("\n");
12	  const selectedClipLines = selectedClips.map((clip) => {
13	    const matchingLine = timelineLines.find((line) => line.includes(`id=${clip.clip_id}`));
14	    const timelineContext = matchingLine ? matchingLine.replace(/^- /, "").trim() : null;
15	
16	    return timelineContext
17	      ? `- ${clip.clip_id} (${clip.media_type}, ${clip.url}) | timeline=${timelineContext}`
18	      : `- ${clip.clip_id} (${clip.media_type}, ${clip.url})`;
19	  });
20	
21	  return `\n\nUser has selected the following clips:\n${selectedClipLines.join("\n")}\nThese clips are the focus of the user's request.`;
22	}
