 28	function buildImageGenerationInput(args: CreateGenerationTaskArgs): Record<string, unknown> | null {
 29	  const legacyInput = isRecord(args.params) ? { ...args.params } : {};
 30	  const prompt = asTrimmedString(args.prompt) ?? asTrimmedString(legacyInput.prompt);
 31	  const count = asPositiveNumber(args.count) ?? asPositiveNumber(legacyInput.count) ?? 1;
 32	  const prompts = Array.isArray(legacyInput.prompts)
 33	    ? legacyInput.prompts
 34	    : (prompt ? [{ id: "prompt-1", fullPrompt: prompt }] : null);
 35	
 36	  if (!prompts) {
 37	    return null;
 38	  }
 39	
 40	  delete legacyInput.prompt;
 41	  delete legacyInput.count;
 42	
 43	  const referenceMode = asTrimmedString(args.reference_mode) ?? asTrimmedString(legacyInput.reference_mode);
 44	  const referenceImageUrl = asTrimmedString(args.reference_image_url)
 45	    ?? asTrimmedString(legacyInput.reference_image_url)
 46	    ?? asTrimmedString(legacyInput.style_reference_image);
 47	  const subjectReferenceImage = asTrimmedString(legacyInput.subject_reference_image) ?? referenceImageUrl;
 48	  const modelName = asTrimmedString(args.model_name)
 49	    ?? asTrimmedString(legacyInput.model_name)
 50	    ?? (referenceMode ? "qwen-image" : null);
 51	  const shotId = asTrimmedString(args.shot_id) ?? asTrimmedString(legacyInput.shot_id);
 52	
 53	  return {
 54	    ...legacyInput,
 55	    prompts,
 56	    imagesPerPrompt: asPositiveNumber(legacyInput.imagesPerPrompt) ?? count,
 57	    ...(referenceMode ? { reference_mode: referenceMode } : {}),
 58	    ...(referenceImageUrl ? { style_reference_image: referenceImageUrl } : {}),
 59	    ...(subjectReferenceImage && referenceMode && referenceMode !== "style"
 60	      ? { subject_reference_image: subjectReferenceImage }
 61	      : {}),
 62	    ...(shotId ? { shot_id: shotId } : {}),
 63	    ...(modelName ? { model_name: modelName } : {}),
 64	  };
 65	}
