 93	function buildCreateTaskRequest(args: CreateGenerationTaskArgs): CreateTaskRequest | null {
 94	  const taskType = asTrimmedString(args.task_type) ?? "image_generation";
 95	  const family = taskType === "travel_between_images" || taskType === "image-to-video"
 96	    ? "travel_between_images"
 97	    : "image_generation";
 98	  const input = family === "travel_between_images"
 99	    ? buildTravelBetweenImagesInput(args)
100	    : buildImageGenerationInput(args);
101	
102	  return input ? { family, input } : null;
103	}
