113	async function sha256Hex(value: string): Promise<string> {
114	  const encoded = new TextEncoder().encode(value);
115	  const digest = await crypto.subtle.digest("SHA-256", encoded);
116	  return Array.from(new Uint8Array(digest))
117	    .map((byte) => byte.toString(16).padStart(2, "0"))
118	    .join("");
119	}
