121	async function getIdempotencyKey(args: CreateGenerationTaskArgs): Promise<string> {
122	  if (typeof args.idempotency_key === "string" && args.idempotency_key.trim()) {
123	    return args.idempotency_key.trim();
124	  }
125	
126	  const payload = JSON.stringify({
127	    project_id: args.project_id,
128	    request: buildCreateTaskRequest(args),
129	  });
130	  const digest = await sha256Hex(payload);
131	  return `timeline-agent:${digest.slice(0, 40)}`;
132	}
