134	export async function createGenerationTask(args: CreateGenerationTaskArgs): Promise<ToolResult> {
135	  if (typeof args.project_id !== "string" || !args.project_id.trim()) {
136	    return { result: "create_generation_task requires project_id." };
137	  }
138	
139	  const request = buildCreateTaskRequest(args);
140	  if (!request) {
141	    return { result: "create_generation_task requires either params or prompt." };
142	  }
143	
144	  const supabaseUrl = requireEnv("SUPABASE_URL");
145	  const serviceRoleKey = requireEnv("SUPABASE_SERVICE_ROLE_KEY");
146	  const idempotencyKey = await getIdempotencyKey(args);
147	
148	  const response = await fetch(`${supabaseUrl}/functions/v1/create-task`, {
149	    method: "POST",
150	    headers: {
151	      "Content-Type": "application/json",
152	      Authorization: `Bearer ${serviceRoleKey}`,
153	      apikey: serviceRoleKey,
154	    },
155	    body: JSON.stringify({
156	      family: request.family,
157	      input: request.input,
158	      project_id: args.project_id.trim(),
159	      dependant_on: null,
160	      idempotency_key: idempotencyKey,
161	    }),
162	  });
163	
164	  if (!response.ok) {
165	    const errorText = await response.text().catch(() => "");
166	    const message = errorText || "Failed to create task";
167	    return { result: `Failed to create task: ${message}` };
168	  }
169	
170	  const data = await response.json() as { task_id?: string; deduplicated?: boolean };
171	  const taskLabel = request.family === "travel_between_images" ? "image-to-video" : "image_generation";
172	
173	  return {
174	    result: data.task_id
175	      ? `Queued ${taskLabel} task ${data.task_id}${data.deduplicated ? " (deduplicated)." : "."}`
176	      : `Queued ${taskLabel} task.`,
177	  };
178	}
