181	  create_generation_task: (args) => createGenerationTask(args),
182	};

 1	import type {
 2	  SelectedClipPayload,
 3	  SupabaseAdmin,
 4	  TimelineState,
 5	  ToolResult,
 6	} from "../types.ts";
 7	import { asPositiveNumber, asStringArray, asTrimmedString } from "../utils.ts";
 8	import { createShotWithGenerations, findShotForGenerations, resolveClipGenerationIds } from "./clips.ts";
 9	import { createGenerationTask } from "./generation.ts";
10	
11	const APPEND_SHOT_POSITION = 2_147_483_647;
12	const SUPPORTED_CREATE_TASK_TYPES = new Set([
13	  "text-to-image",
14	  "style-transfer",
15	  "subject-transfer",
16	  "scene-transfer",
17	  "image-to-video",
18	]);
19	const TASK_TYPE_TO_REFERENCE_MODE: Record<string, string> = {
20	  "style-transfer": "style",
21	  "subject-transfer": "subject",
22	  "scene-transfer": "scene",
23	};
24	
25	export async function executeCreateTask(
26	  args: Record<string, unknown>,
27	  timelineState: TimelineState,
28	  selectedClips: SelectedClipPayload[] | undefined,
29	  supabaseAdmin: SupabaseAdmin,
30	): Promise<Pick<ToolResult, "result">> {
31	  const taskType = asTrimmedString(args.task_type);
32	  const prompt = asTrimmedString(args.prompt);
33	  if (!taskType || !prompt) {
34	    return { result: "create_task requires task_type and prompt." };
35	  }
36	  if (!SUPPORTED_CREATE_TASK_TYPES.has(taskType)) {
37	    return { result: `create_task does not support task_type ${taskType}.` };
38	  }
39	
40	  const referenceImageUrls = asStringArray(args.reference_image_urls);
41	  if (taskType === "image-to-video" && referenceImageUrls.length < 2) {
42	    return { result: "create_task image-to-video requires at least two reference_image_urls." };
43	  }
44	  if (taskType !== "text-to-image" && taskType !== "image-to-video" && referenceImageUrls.length === 0) {
45	    return { result: `create_task ${taskType} requires reference_image_urls.` };
46	  }
47	
48	  const selectedReferenceClips = selectedClips?.filter((clip) => referenceImageUrls.includes(clip.url)) ?? [];
49	  const generationIds = resolveClipGenerationIds(selectedReferenceClips, timelineState.registry, timelineState.config);
50	  let shotId = generationIds.length ? await findShotForGenerations(supabaseAdmin, generationIds) : null;
51	  let shotNote = "";
52	  const shotName = asTrimmedString(args.shot_name);
53	  if (!shotId && shotName && generationIds.length > 0) {
54	    shotId = await createShotWithGenerations(supabaseAdmin, {
55	      projectId: timelineState.projectId,
56	      shotName,
57	      generationIds,
58	      position: APPEND_SHOT_POSITION,
59	    });
60	    shotNote = ` Created shot ${shotName} (${shotId}).`;
61	  } else if (shotId) {
62	    shotNote = ` Reused shot ${shotId}.`;
63	  }
64	
65	  const result = await createGenerationTask({
66	    project_id: timelineState.projectId,
67	    prompt,
68	    count: asPositiveNumber(args.count) ?? 1,
69	    task_type: taskType,
70	    reference_mode: TASK_TYPE_TO_REFERENCE_MODE[taskType],
71	    reference_image_url: referenceImageUrls[0],
72	    image_urls: taskType === "image-to-video" ? referenceImageUrls : undefined,
73	    shot_id: shotId ?? undefined,
74	  });
75	  return { result: `${result.result}${shotNote}`.trim() };
76	}

