 99	function expandArrayToCount<T>(values: T[] | undefined, count: number): T[] | undefined {
100	  if (!values || values.length === 0) return values;
101	  if (values.length === count) return values;
102	  if (values.length === 1) {
103	    return Array.from({ length: count }, () => values[0]);
104	  }
105	  return values;
106	}
