108	async function ensureShotParentGenerationId(
109	  context: Parameters<TaskFamilyResolver>[1],
110	  input: TravelBetweenImagesTaskInput,
111	): Promise<string | undefined> {
112	  if (input.parent_generation_id) {
113	    return input.parent_generation_id;
114	  }
115	  if (!input.shot_id) {
116	    return undefined;
117	  }
118	
119	  const { data, error } = await context.supabaseAdmin.rpc("ensure_shot_parent_generation", {
120	    p_shot_id: input.shot_id,
121	    p_project_id: context.projectId,
122	  });
123	
124	  if (error) {
125	    throw new Error(`Failed to ensure parent generation for shot ${input.shot_id}: ${error.message}`);
126	  }
127	  if (!data || typeof data !== "string") {
128	    throw new Error(`ensure_shot_parent_generation returned invalid parent ID for shot ${input.shot_id}`);
129	  }
130	  return data;
131	}
