192	function resolveExecutionMode(
193	  spec: ModelSpec,
194	  intent: ResolveGenerationPolicyIntent,
195	): ExecutionMode {
196	  if (spec.modelFamily === 'ltx') {
197	    return 'i2v';
198	  }
199	
200	  if (intent.guidanceKind === 'uni3c') {
201	    return 'i2v';
202	  }
203	
204	  if (
205	    intent.guidanceKind === 'flow'
206	    || intent.guidanceKind === 'canny'
207	    || intent.guidanceKind === 'depth'
208	    || intent.guidanceKind === 'raw'
209	  ) {
210	    return 'vace';
211	  }
212	
213	  return intent.requestedExecutionMode;
214	}
215	
216	export function resolveContinuationPolicy(
217	  spec: ModelSpec,
218	  intent: ResolveGenerationPolicyIntent,
219	): ResolvedContinuationPolicy {
220	  const executionMode = resolveExecutionMode(spec, intent);
221	  const strategy = intent.smoothContinuations
222	    ? spec.continuationByExecutionMode[executionMode]
223	    : undefined;
224	
225	  if (!strategy) {
226	    return {
227	      enabled: false,
228	      overlapFrames: DEFAULT_FRAME_OVERLAP,
229	      maxOutputFrames: spec.maxFrames,
230	    };
231	  }
232	
233	  return {
234	    enabled: true,
235	    strategy,
236	    overlapFrames: CONTINUATION_LIMITS[strategy].overlapFrames,
237	    maxOutputFrames: CONTINUATION_LIMITS[strategy].maxOutputFrames,
238	  };
239	}
240	
241	export function clampFrameCountToPolicy(
242	  frames: number,
243	  spec: ModelSpec,
244	  intent: ResolveGenerationPolicyIntent,
245	  minFrames: number = 9,
246	): number {
247	  const { maxOutputFrames } = resolveContinuationPolicy(spec, intent);
248	  const safeFrames = Number.isFinite(frames) ? frames : spec.defaultFrames;
249	  return Math.min(
250	    quantizeFrameCount(Math.max(safeFrames, minFrames), minFrames, spec.frameStep),
251	    maxOutputFrames,
252	  );
253	}
254	
255	export function resolveGenerationPolicy(
256	  spec: ModelSpec,
257	  intent: ResolveGenerationPolicyIntent,
258	): ResolvedGenerationPolicy {
259	  const travelMode = resolveExecutionMode(spec, intent);
260	  const continuation = resolveContinuationPolicy(spec, intent);
261	
262	  return {
263	    travelMode,
264	    continuation,
265	    frameOverlap: continuation.overlapFrames,
266	  };
267	}

