 70	function parseEnvFile(contents: string): Record<string, string> {
 71	  const parsed: Record<string, string> = {};
 72	  for (const rawLine of contents.split(/\r?\n/)) {
 73	    const line = rawLine.trim();
 74	    if (!line || line.startsWith("#")) continue;
 75	    const normalized = line.startsWith("export ") ? line.slice(7) : line;
 76	    const separatorIndex = normalized.indexOf("=");
 77	    if (separatorIndex <= 0) continue;
 78	    const key = normalized.slice(0, separatorIndex).trim();
 79	    const value = normalized.slice(separatorIndex + 1).trim().replace(/^["']|["']$/g, "");
 80	    if (key) parsed[key] = value;
 81	  }
 82	  return parsed;
 83	}
