 85	function readOptionalEnvValue(key: string): string | undefined {
 86	  const direct = process.env[key]?.trim();
 87	  if (direct) return direct;
 88	  const envFile = process.env.HARNESS_ENV_FILE?.trim()
 89	    ? path.resolve(process.cwd(), process.env.HARNESS_ENV_FILE)
 90	    : path.join(getReighAppRoot(), ".env.local");
 91	  if (!existsSync(envFile)) return undefined;
 92	  return parseEnvFile(readFileSync(envFile, "utf8"))[key]?.trim();
 93	}
