 95	function parseArgs(argv: string[]): AgenticRunnerOptions | { help: true } {
 96	  const options: AgenticRunnerOptions = { rounds: 3, dryRun: false, maxTasks: 5 };
 97	  for (let index = 0; index < argv.length; index += 1) {
 98	    const arg = argv[index];
 99	    if (arg === "--help" || arg === "-h") return { help: true };
100	    if (arg === "--dry-run") {
101	      options.dryRun = true;
102	      continue;
103	    }
104	    if (arg === "--timeline-id") {
105	      const value = argv[index + 1];
106	      if (!value) throw new Error("--timeline-id requires a value");
107	      options.timelineId = value;
108	      index += 1;
109	      continue;
110	    }
111	    if (arg === "--rounds") {
112	      const value = Number(argv[index + 1]);
113	      if (!Number.isInteger(value) || value < 1) throw new Error("--rounds must be a positive integer");
114	      options.rounds = value;
115	      index += 1;
116	      continue;
117	    }
118	    if (arg === "--max-tasks") {
119	      const value = Number(argv[index + 1]);
120	      if (!Number.isInteger(value) || value < 0) throw new Error("--max-tasks must be a non-negative integer");
121	      options.maxTasks = value;
122	      index += 1;
123	      continue;
124	    }
125	    throw new Error(`Unknown argument: ${arg}`);
126	  }
127	  return options;
128	}
