182	async function callAnthropicJson<T>(system: string, prompt: string): Promise<T> {
183	  const apiKey = readOptionalEnvValue("ANTHROPIC_API_KEY");
184	  if (!apiKey) {
185	    throw new Error("Missing ANTHROPIC_API_KEY in the environment or harness env file.");
186	  }
187	
188	  const response = await fetch("https://api.anthropic.com/v1/messages", {
189	    method: "POST",
190	    headers: {
191	      "content-type": "application/json",
192	      "x-api-key": apiKey,
193	      "anthropic-version": "2023-06-01",
194	    },
195	    body: JSON.stringify({
196	      model: readOptionalEnvValue("ANTHROPIC_MODEL") ?? "claude-3-7-sonnet-latest",
197	      max_tokens: 2_000,
198	      system,
199	      messages: [{ role: "user", content: prompt }],
200	    }),
201	  });
202	
203	  const payload = await response.json();
204	  if (!response.ok) {
205	    throw new Error(`Anthropic request failed: ${response.status} ${JSON.stringify(payload)}`);
206	  }
207	
208	  const content = Array.isArray((payload as { content?: unknown }).content)
209	    ? ((payload as { content: Array<{ type: string; text?: string }> }).content
210	      .filter((block) => block.type === "text")
211	      .map((block) => block.text ?? "")
212	      .join("\n"))
213	    : "";
214	  return parseJsonResponse<T>(content);
215	}
