254	function buildSelectedClips(snapshot: HarnessSnapshot, indexes: number[]): Array<{ clip_id: string; url: string; media_type: "image" | "video"; generation_id?: string }> {
255	  const timeline = getTimeline(snapshot);
256	  const registry = timeline.asset_registry as { assets?: Record<string, { file?: string; type?: string; generationId?: string }> };
257	  return indexes.flatMap((index) => {
258	    const clip = timeline.config.clips[index];
259	    const asset = clip?.asset ? registry.assets?.[clip.asset] : undefined;
260	    if (!clip || !asset?.file) return [];
261	    return [{
262	      clip_id: clip.id,
263	      url: asset.file,
264	      media_type: asset.type?.startsWith("video/") ? "video" : "image",
265	      ...(asset.generationId ? { generation_id: asset.generationId } : {}),
266	    }];
267	  });
