371	export async function runAgenticSuite(options: AgenticRunnerOptions): Promise<AgenticRunReport> {
372	  const baseline = await loadBaselineContext(options);
373	  const rounds: RoundReport[] = [];
374	  let tasksUsed = 0;
375	
376	  for (let round = 1; round <= options.rounds; round += 1) {
377	    const generated = await callAnthropicJson<{ cases: GeneratedCase[] }>(
378	      "You are designing timeline-agent QA cases. Return JSON only.",
379	      [
380	        `Round ${round}.`,
381	        `Dry run: ${options.dryRun}.`,
382	        `Remaining generation budget: ${Math.max(0, options.maxTasks - tasksUsed)}.`,
383	        "Do not propose compound generate-and-place cases.",
384	        "Use clip indexes from the summary when you need selected clips.",
385	        'Return {"cases":[...]} with up to 4 cases. Each case needs name, category, message, selected_clip_indexes, requires_generation, estimated_generation_tasks, expected_outcome.',
386	        summarizeSnapshot(baseline.snapshot),
387	      ].join("\n\n"),
388	    );
389	
390	    const executedCases: ExecutedCaseResult[] = [];
391	    for (const generatedCase of generated.cases ?? []) {
392	      const { result, taskDelta } = await executeGeneratedCase(generatedCase, baseline.timelineConfig, options, tasksUsed);
393	      tasksUsed += taskDelta;
394	      executedCases.push(result);
395	    }
396	
397	    const analysis = await callAnthropicJson<RoundAnalysis>(
398	      "You are reviewing timeline-agent QA results. Return JSON only.",
399	      JSON.stringify({
400	        dry_run: options.dryRun,
401	        remaining_generation_budget: Math.max(0, options.maxTasks - tasksUsed),
402	        generated_cases: generated.cases ?? [],
403	        executed_cases: executedCases,
404	      }, null, 2),
405	    );
406	
407	    rounds.push({
408	      round,
409	      generated_cases: generated.cases ?? [],
410	      executed_cases: executedCases,
411	      analysis,
412	    });
413	  }
414	
415	  const reportPath = reportPathFor("agentic-runner-report");
416	  const report: AgenticRunReport = {
417	    generated_at: new Date().toISOString(),
418	    timeline_source: baseline.source,
419	    dry_run: options.dryRun,
420	    max_tasks: options.maxTasks,
421	    tasks_used: tasksUsed,
422	    rounds,
423	    report_path: reportPath,
424	  };
425	  writeFileSync(reportPath, `${JSON.stringify(report, null, 2)}\n`, "utf8");
426	  console.table(rounds.map((round) => ({
427	    round: round.round,
428	    generated_cases: round.generated_cases.length,
429	    executed_cases: round.executed_cases.length,
430	    failure_patterns: round.analysis.failure_patterns.length,
431	    suggested_next_steps: round.analysis.suggested_next_steps.length,
432	  })));
433	  console.log(`Wrote agentic report to ${reportPath}`);
434	  return report;
435	}
