 57	function parseArgs(argv: string[]): RunTestSuiteOptions | { help: true } {
 58	  const options: RunTestSuiteOptions = {};
 59	
 60	  for (let index = 0; index < argv.length; index += 1) {
 61	    const arg = argv[index];
 62	    if (arg === "--help" || arg === "-h") {
 63	      return { help: true };
 64	    }
 65	    if (arg === "--skip-generations") {
 66	      options.skipGenerations = true;
 67	      continue;
 68	    }
 69	    if (arg === "--category") {
 70	      const value = argv[index + 1];
 71	      if (!value || (value !== "timeline-edit" && value !== "generation" && value !== "error-handling")) {
 72	        throw new Error("--category must be one of: timeline-edit, generation, error-handling");
 73	      }
 74	      options.category = value;
 75	      index += 1;
 76	      continue;
 77	    }
 78	    if (arg === "--case") {
 79	      const value = argv[index + 1];
 80	      if (!value) {
 81	        throw new Error("--case requires a value");
 82	      }
 83	      options.caseName = value;
 84	      index += 1;
 85	      continue;
 86	    }
 87	
 88	    throw new Error(`Unknown argument: ${arg}`);
 89	  }
 90	
 91	  return options;
 92	}
