140	async function runSingleCase(
141	  testCase: TestCase,
142	  options: RunTestSuiteOptions,
143	): Promise<TestCaseRunResult> {
144	  const harness = new TestHarness();
145	  const startedAt = Date.now();
146	
147	  try {
148	    await harness.setup();
149	    const before = await harness.snapshot();
150	    await testCase.setup?.(before);
151	
152	    const message = resolveCaseMessage(testCase, before);
153	    const selectedClips = resolveCaseSelectedClips(testCase, before);
154	    const responses = await harness.sendMessage(message, selectedClips);
155	
156	    if (!options.skipGenerations && !testCase.skipTaskCompletion) {
157	      await harness.waitForSideEffects({
158	        taskTimeoutMs: testCase.timeoutMs,
159	        generationTimeoutMs: testCase.timeoutMs,
160	        creditsTimeoutMs: testCase.timeoutMs ? Math.min(testCase.timeoutMs, 30_000) : undefined,
161	      });
162	    }
163	
164	    const after = await harness.snapshot();
165	    const diff = harness.diff(before, after);
166	    const evaluation = testCase.evaluate({ before, after, diff });
167	    const taskIds = extractNewTaskIds(before, after);
168	    const status = evaluation.failed === 0 ? "passed" : "failed";
169	
170	    return {
171	      name: testCase.name,
172	      category: testCase.category,
173	      status,
174	      score: evaluation.score,
175	      passed: evaluation.passed,
176	      failed: evaluation.failed,
177	      wall_time_ms: Date.now() - startedAt,
178	      reinvocations: Math.max(0, responses.length - 1),
179	      tasks_created: taskIds.length,
180	      task_ids: taskIds,
181	      assertion_details: evaluation.details,
182	      agent_statuses: responses.map((response) => response.status),
183	      diff_summary: harness.summarizeDiff(diff),
184	    };
185	  } catch (error) {
186	    const message = error instanceof Error ? error.message : String(error);
187	    return {
188	      name: testCase.name,
189	      category: testCase.category,
190	      status: "error",
191	      score: 0,
192	      passed: 0,
193	      failed: 1,
194	      wall_time_ms: Date.now() - startedAt,
195	      reinvocations: 0,
196	      tasks_created: 0,
197	      task_ids: [],
198	      assertion_details: [{ pass: false, reason: message }],
199	      agent_statuses: [],
200	      error: message,
201	    };
202	  } finally {
203	    await harness.teardown();
204	  }
205	}
