  1	/**
  2	 * Diverse generation test — exercises every generation type the timeline agent supports.
  3	 *
  4	 * Verifies task CREATION only (does not wait for GPU completion).
  5	 * Run: cd reigh-app && npx tsx supabase/functions/_tests/harness/diverse-gen-test.ts
  6	 */
  7	
  8	import type { SelectedClipPayload } from "../../ai-timeline-agent/types.ts";
  9	import { TestHarness, createTestSession, callAgentUntilSettled, signInHarnessUser } from "./index.ts";
 10	import type { HarnessSnapshot, SnapshotDiff, TaskSnapshotRow } from "./snapshot.ts";
 11	
 12	// ---------------------------------------------------------------------------
 13	// Types
 14	// ---------------------------------------------------------------------------
 15	
 16	interface GenTestCase {
 17	  label: string;
 18	  expectedTaskType: string;
 19	  message: string | ((snapshot: HarnessSnapshot) => string);
 20	  selectedClips?: (snapshot: HarnessSnapshot) => SelectedClipPayload[];
 21	  /** Extra checks on the created task's params JSON */
 22	  validateTask?: (task: TaskSnapshotRow) => string | null; // null = ok, string = error
 23	}
 24	
 25	interface GenTestResult {
 26	  label: string;
 27	  expectedTaskType: string;
 28	  actualTaskType: string | null;
 29	  taskId: string | null;
 30	  taskStatus: string | null;
 31	  keyParams: Record<string, unknown>;
 32	  sessionStatus: string | null;
 33	  error: string | null;
 34	  durationMs: number;
 35	}
 36	
 37	// ---------------------------------------------------------------------------
 38	// Helpers
 39	// ---------------------------------------------------------------------------
 40	
 41	function buildSelectedClip(snapshot: HarnessSnapshot, clipIndex: number): SelectedClipPayload {
 42	  const timeline = Object.values(snapshot.timelines)[0];
 43	  if (!timeline) throw new Error("No timeline in snapshot");
 44	
 45	  const clip = timeline.config.clips[clipIndex];
 46	  if (!clip) throw new Error(`No clip at index ${clipIndex}`);
 47	  if (!clip.asset) throw new Error(`Clip ${clip.id} has no asset`);
 48	
 49	  const registry = timeline.asset_registry as { assets: Record<string, { file: string; type?: string; generationId?: string }> };
 50	  const asset = registry.assets[clip.asset];
 51	  if (!asset?.file) throw new Error(`Asset ${clip.asset} missing file`);
 52	
 53	  return {
 54	    clip_id: clip.id,
 55	    url: asset.file,
 56	    media_type: asset.type?.startsWith("video/") ? "video" : "image",
 57	    ...(asset.generationId ? { generation_id: asset.generationId } : {}),
 58	  };
 59	}
 60	
 61	function findAddedTask(diff: SnapshotDiff): TaskSnapshotRow | null {
 62	  const added = Object.values(diff.tasks.added);
 63	  return added.length > 0 ? added[0] : null;
 64	}
 65	
 66	function getSessionStatus(snapshot: HarnessSnapshot): string | null {
 67	  const sessions = Object.values(snapshot.timeline_agent_sessions);
 68	  if (sessions.length === 0) return null;
 69	  return sessions[sessions.length - 1].status;
 70	}
 71	
 72	function extractKeyParams(task: TaskSnapshotRow): Record<string, unknown> {
 73	  const params = task.params as Record<string, unknown> | null;
 74	  if (!params) return {};
 75	
 76	  const keys: Record<string, unknown> = {};
 77	  if (params.prompts) keys.prompts = params.prompts;
 78	  if (params.reference_mode) keys.reference_mode = params.reference_mode;
 79	  if (params.style_reference_image) keys.style_reference_image = String(params.style_reference_image).slice(0, 60) + "...";
 80	  if (params.subject_reference_image) keys.subject_reference_image = String(params.subject_reference_image).slice(0, 60) + "...";
 81	  if (params.model_name) keys.model_name = params.model_name;
 82	  if (params.image_urls) keys.image_urls = (params.image_urls as string[]).map((u) => u.slice(0, 60) + "...");
 83	  if (params.base_prompts) keys.base_prompts = params.base_prompts;
 84	  if (params.shot_id) keys.shot_id = params.shot_id;
 85	  if (params.imagesPerPrompt) keys.imagesPerPrompt = params.imagesPerPrompt;
 86	  return keys;
 87	}
 88	
 89	// ---------------------------------------------------------------------------
 90	// Test cases
 91	// ---------------------------------------------------------------------------
 92	
 93	const testCases: GenTestCase[] = [
 94	  {
 95	    label: "text-to-image",
 96	    // The create-task edge function maps text-to-image to the actual GPU task type
 97	    // which may be "wan_2_2_t2i", "image_generation", etc. — we accept any non-null.
 98	    expectedTaskType: "*",
 99	    message: "Generate an image of a futuristic city at sunset",
100	    validateTask: (task) => {
101	      // The task was created — verify it exists and has a prompt-related param
102	      const params = task.params as Record<string, unknown>;
103	      const paramsStr = JSON.stringify(params).toLowerCase();
104	      if (!paramsStr.includes("futuristic") && !paramsStr.includes("city") && !paramsStr.includes("sunset")) {
105	        return "Task params don't seem to contain the prompt content";
106	      }
107	      return null;
108	    },
109	  },
110	  {
111	    label: "image-to-video",
112	    // The create-task edge function maps image-to-video to "travel_orchestrator" or similar
113	    expectedTaskType: "*",
114	    message: (snapshot) => {
115	      const clip0 = buildSelectedClip(snapshot, 0);
116	      const clip1 = buildSelectedClip(snapshot, 1);
117	      return `Convert these clips into a video traveling between them: ${clip0.url} and ${clip1.url}`;
118	    },
119	    selectedClips: (snapshot) => [buildSelectedClip(snapshot, 0), buildSelectedClip(snapshot, 1)],
120	    validateTask: (task) => {
121	      const params = task.params as Record<string, unknown>;
122	      // Should have image_urls with at least 2 entries
123	      if (params.image_urls && Array.isArray(params.image_urls) && (params.image_urls as string[]).length >= 2) {
124	        return null;
125	      }
126	      // Or the task type itself indicates video generation
127	      if (task.task_type.includes("travel") || task.task_type.includes("video") || task.task_type.includes("i2v")) {
128	        return null;
129	      }
130	      return `Expected video-related task or image_urls with 2+ entries, got task_type=${task.task_type}`;
131	    },
132	  },
133	  {
134	    label: "subject-transfer",
135	    // Maps to qwen_image_style or similar via the create-task edge function
136	    expectedTaskType: "*",
137	    message: (snapshot) => {
138	      const clip0 = buildSelectedClip(snapshot, 0);
139	      return `Generate an image using the subject from selected clip ${clip0.clip_id} but place it in a forest setting`;
140	    },
141	    selectedClips: (snapshot) => [buildSelectedClip(snapshot, 0)],
142	    validateTask: (task) => {
143	      const params = task.params as Record<string, unknown>;
144	      // For subject-transfer, we expect reference_mode=subject or subject_reference_image
145	      if (params.reference_mode === "subject" || params.subject_reference_image) return null;
146	      // Accept if it's at least a reference-based generation
147	      if (params.style_reference_image || params.reference_mode) return null;
148	      return `Expected subject-transfer params (reference_mode=subject or subject_reference_image), got: ${JSON.stringify(Object.keys(params))}`;
149	    },
150	  },
151	  {
152	    label: "scene-transfer",
153	    // Maps to qwen_image_style or similar via the create-task edge function
154	    expectedTaskType: "*",
155	    message: (snapshot) => {
156	      const clip0 = buildSelectedClip(snapshot, 0);
157	      return `Generate an image using the scene/background from selected clip ${clip0.clip_id} with a robot in it`;
158	    },
159	    selectedClips: (snapshot) => [buildSelectedClip(snapshot, 0)],
160	    validateTask: (task) => {
161	      const params = task.params as Record<string, unknown>;
162	      // For scene-transfer, we expect reference_mode=scene
163	      if (params.reference_mode === "scene") return null;
164	      // Accept if it's at least a reference-based generation
165	      if (params.style_reference_image || params.reference_mode || params.subject_reference_image) return null;
166	      return `Expected scene-transfer params (reference_mode=scene), got: ${JSON.stringify(Object.keys(params))}`;
167	    },
168	  },
169	];
170	
171	// ---------------------------------------------------------------------------
172	// Runner
173	// ---------------------------------------------------------------------------
174	
175	async function runTest(
176	  harness: TestHarness,
177	  testCase: GenTestCase,
178	  baseSnapshot: HarnessSnapshot,
179	  setupInfo: { timelineId: string; userId: string },
180	): Promise<GenTestResult> {
181	  const start = Date.now();
182	  const result: GenTestResult = {
183	    label: testCase.label,
184	    expectedTaskType: testCase.expectedTaskType,
185	    actualTaskType: null,
186	    taskId: null,
187	    taskStatus: null,
188	    keyParams: {},
189	    sessionStatus: null,
190	    error: null,
191	    durationMs: 0,
192	  };
193	
194	  try {
195	    const message = typeof testCase.message === "function"
196	      ? testCase.message(baseSnapshot)
197	      : testCase.message;
198	    const selectedClips = testCase.selectedClips?.(baseSnapshot);
199	
200	    console.log(`\n--- [${testCase.label}] Sending: "${message.slice(0, 80)}..."`);
201	    if (selectedClips?.length) {
202	      console.log(`    Selected clips: ${selectedClips.map((c) => c.clip_id).join(", ")}`);
203	    }
204	
205	    // Create a fresh session per test to avoid deduplication / context leakage
206	    const freshSession = await createTestSession(setupInfo.timelineId, setupInfo.userId);
207	    const auth = await signInHarnessUser();
208	
209	    const beforeSnapshot = await harness.snapshot();
210	    const responses = await callAgentUntilSettled(
211	      freshSession.sessionId,
212	      message,
213	      selectedClips,
214	      { jwt: auth.jwt },
215	    );
216	    const lastResponse = responses[responses.length - 1];
217	    console.log(`    Agent status: ${lastResponse?.status}, turns: ${responses.length}`);
218	
219	    const afterSnapshot = await harness.snapshot();
220	    const diff = harness.diff(beforeSnapshot, afterSnapshot);
221	    const addedTask = findAddedTask(diff);
222	
223	    result.sessionStatus = getSessionStatus(afterSnapshot);
224	
225	    if (!addedTask) {
226	      result.error = "No task was created";
227	    } else {
228	      result.taskId = addedTask.id;
229	      result.actualTaskType = addedTask.task_type;
230	      result.taskStatus = addedTask.status;
231	      result.keyParams = extractKeyParams(addedTask);
232	
233	      if (testCase.expectedTaskType !== "*" && addedTask.task_type !== testCase.expectedTaskType) {
234	        result.error = `Task type mismatch: expected ${testCase.expectedTaskType}, got ${addedTask.task_type}`;
235	      }
236	
237	      if (!result.error && testCase.validateTask) {
238	        const validationError = testCase.validateTask(addedTask);
239	        if (validationError) {
240	          result.error = validationError;
241	        }
242	      }
243	    }
244	
245	    console.log(`    Task: ${result.taskId ?? "none"} (${result.actualTaskType ?? "n/a"}) status=${result.taskStatus ?? "n/a"}`);
246	    if (result.error) {
247	      console.log(`    ERROR: ${result.error}`);
248	    }
249	  } catch (err) {
250	    result.error = err instanceof Error ? err.message : String(err);
251	    console.log(`    EXCEPTION: ${result.error}`);
252	  }
253	
254	  result.durationMs = Date.now() - start;
255	  return result;
256	}
257	
258	// ---------------------------------------------------------------------------
259	// Main
260	// ---------------------------------------------------------------------------
261	
262	async function main() {
263	  console.log("=== Diverse Generation Test ===\n");
264	
265	  const harness = new TestHarness();
266	  const results: GenTestResult[] = [];
267	
268	  try {
269	    console.log("Setting up harness...");
270	    const setup = await harness.setup();
271	    console.log(`  Project: ${setup.projectId}`);
272	    console.log(`  Timeline: ${setup.timelineId}`);
273	    console.log(`  Session: ${setup.sessionId}`);
274	
275	    const baseSnapshot = await harness.snapshot();
276	    console.log(`  Clips: ${Object.values(baseSnapshot.timelines)[0]?.config.clips.length ?? 0}`);
277	
278	    for (const testCase of testCases) {
279	      const result = await runTest(harness, testCase, baseSnapshot, {
280	        timelineId: setup.timelineId,
281	        userId: setup.userId,
282	      });
283	      results.push(result);
284	    }
285	  } finally {
286	    console.log("\nTearing down harness...");
287	    await harness.teardown();
288	  }
289	
290	  // Summary table
291	  console.log("\n\n=== SUMMARY ===\n");
292	  const colWidths = { label: 20, type: 24, taskId: 38, status: 12, session: 14, time: 8, result: 8 };
293	  const header = [
294	    "Label".padEnd(colWidths.label),
295	    "Task Type".padEnd(colWidths.type),
296	    "Task ID".padEnd(colWidths.taskId),
297	    "Status".padEnd(colWidths.status),
298	    "Session".padEnd(colWidths.session),
299	    "Time".padEnd(colWidths.time),
300	    "Result".padEnd(colWidths.result),
301	  ].join(" | ");
302	  console.log(header);
303	  console.log("-".repeat(header.length));
304	
305	  let passed = 0;
306	  let failed = 0;
307	
308	  for (const r of results) {
309	    const ok = !r.error;
310	    if (ok) passed++;
311	    else failed++;
312	
313	    const row = [
314	      r.label.padEnd(colWidths.label),
315	      (r.actualTaskType ?? "NONE").padEnd(colWidths.type),
316	      (r.taskId ?? "—").padEnd(colWidths.taskId),
317	      (r.taskStatus ?? "—").padEnd(colWidths.status),
318	      (r.sessionStatus ?? "—").padEnd(colWidths.session),
319	      `${(r.durationMs / 1000).toFixed(1)}s`.padEnd(colWidths.time),
320	      (ok ? "PASS" : "FAIL").padEnd(colWidths.result),
321	    ].join(" | ");
322	    console.log(row);
323	  }
324	
325	  console.log("-".repeat(header.length));
326	  console.log(`\nTotal: ${results.length} | Passed: ${passed} | Failed: ${failed}\n`);
327	
328	  // Print key params for each
329	  console.log("=== KEY PARAMS ===\n");
330	  for (const r of results) {
331	    console.log(`[${r.label}]`);
332	    if (r.error) console.log(`  Error: ${r.error}`);
333	    console.log(`  Params: ${JSON.stringify(r.keyParams, null, 2)}`);
334	    console.log();
335	  }
336	
337	  if (failed > 0) {
338	    process.exit(1);
339	  }
340	}
341	
342	main().catch((err) => {
343	  console.error("Fatal error:", err);
344	  process.exit(2);
345	});

